 {"id":"coding_agent_usage_tracker-0o5","title":"Offline: Add fallback logic with fetch strategies","description":"## Summary
Implement fallback logic that returns cached data when network fetches fail.

## Background
The cache layer stores data; this task implements the fetch-with-fallback pattern:
1. Try network fetch
2. On failure, return cached data
3. Mark data as stale
4. Continue operating

## Technical Design

### Fetch with Fallback
```rust
pub struct FallbackFetcher {
    inner_fetcher: Box<dyn UsageFetcher>,
    cache: OfflineCache,
}

impl FallbackFetcher {
    pub async fn fetch(&self, provider: &str) -> FetchOutcome {
        // Try network fetch
        match self.inner_fetcher.fetch(provider).await {
            Ok(payload) => {
                // Update cache on success
                self.cache.set(provider, &payload).ok();

                FetchOutcome {
                    payload,
                    source: DataSource::Live,
                    staleness: Staleness::Fresh,
                    error: None,
                }
            }
            Err(fetch_error) => {
                // Try cache fallback
                self.fallback_to_cache(provider, fetch_error)
            }
        }
    }

    fn fallback_to_cache(&self, provider: &str, error: FetchError) -> FetchOutcome {
        match self.cache.get(provider) {
            Some(entry) => {
                FetchOutcome {
                    payload: entry.payload,
                    source: DataSource::Cached,
                    staleness: entry.staleness(),
                    error: Some(error),
                }
            }
            None => {
                FetchOutcome {
                    payload: ProviderPayload::unavailable(provider),
                    source: DataSource::None,
                    staleness: Staleness::VeryStale { age: Duration::MAX },
                    error: Some(error),
                }
            }
        }
    }
}
```

### Fetch Outcome
```rust
#[derive(Debug)]
pub struct FetchOutcome {
    pub payload: ProviderPayload,
    pub source: DataSource,
    pub staleness: Staleness,
    pub error: Option<FetchError>,
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub enum DataSource {
    Live,       // Fresh from network
    Cached,     // From cache (may be stale)
    None,       // No data available
}

impl FetchOutcome {
    pub fn is_live(&self) -> bool {
        self.source == DataSource::Live
    }

    pub fn is_cached(&self) -> bool {
        self.source == DataSource::Cached
    }

    pub fn is_usable(&self) -> bool {
        self.source != DataSource::None
    }

    pub fn had_error(&self) -> bool {
        self.error.is_some()
    }
}
```

### Network Detection
```rust
pub struct NetworkChecker;

impl NetworkChecker {
    /// Quick check if network is likely available
    pub async fn is_available(&self) -> bool {
        // Try to reach a reliable endpoint
        let client = reqwest::Client::builder()
            .timeout(Duration::from_secs(2))
            .build()
            .ok();

        if let Some(client) = client {
