### Fetch Strategy
```rust
pub enum FetchStrategy {
    NetworkOnly,           // Fail if network unavailable
    NetworkWithFallback,   // Try network, fall back to cache
    CacheFirst,            // Use cache if fresh, else fetch
    CacheOnly,             // Only use cache, never fetch
}

impl FallbackFetcher {
    pub async fn fetch_with_strategy(
        &self,
        provider: &str,
        strategy: FetchStrategy,
    ) -> FetchOutcome {
        match strategy {
            FetchStrategy::NetworkOnly => {
                self.fetch_network_only(provider).await
            }
            FetchStrategy::NetworkWithFallback => {
                self.fetch(provider).await  // Default behavior
            }
            FetchStrategy::CacheFirst => {
                if let Some(entry) = self.cache.get(provider) {
                    if entry.is_fresh() {
                        return FetchOutcome::from_cache(entry);
                    }
                }
                self.fetch(provider).await
            }
            FetchStrategy::CacheOnly => {
                self.cache.get(provider)
                    .map(FetchOutcome::from_cache)
                    .unwrap_or_else(|| FetchOutcome::unavailable(provider))
            }
        }
    }
}
